// checkResultToTerm maps the Engine.CheckPermission return value to a Rego
// boolean term. nil error → granted (true). authz.ErrPermissionDenied or
// authz.ErrConditionalPermission → denied (false) — these are policy
// signals, not system errors. Any other error propagates as types.NewErr
// so the Rego eval fails distinctly from policy denial (per SPEC-013 C4).
func checkResultToTerm(err error) (*ast.Term, error) {
	if err == nil {
		return ast.BooleanTerm(true), nil
	}
	if errors.Is(err, authz.ErrPermissionDenied) || errors.Is(err, authz.ErrConditionalPermission) {
		return ast.BooleanTerm(false), nil
	}
	return nil, fmt.Errorf("CheckPermission: %v", err)
}

// parseSubject splits a "type:id" string into its parts.
func parseSubject(s string) (string, string, error) {
	for i := 0; i < len(s); i++ {
		if s[i] == ':' {
			if i == 0 || i == len(s)-1 {
				return "", "", errMalformedSubject
			}
			return s[:i], s[i+1:], nil
		}
	}
	return "", "", errMalformedSubject
}

var errMalformedSubject = subjectError("subject must be in the form \"type:id\"")

type subjectError string

func (e subjectError) Error() string { return string(e) }

// termToStructpb converts an OPA ast.Term holding an Object to a
// *structpb.Struct. Returns (nil, nil) for empty objects so the caller
// dispatches to the no-caveat Engine path. Returns an error if the term
// is not an Object or contains values not representable in structpb.
func termToStructpb(t *ast.Term) (*structpb.Struct, error) {
	obj, ok := t.Value.(ast.Object)
	if !ok {
		return nil, errMalformedCaveatContext
	}
	if obj.Len() == 0 {
		return nil, nil
	}
	m := make(map[string]any, obj.Len())
	var iterErr error
	obj.Foreach(func(k, v *ast.Term) {
		if iterErr != nil {
			return
		}
		ks, ok := k.Value.(ast.String)
		if !ok {
			iterErr = errMalformedCaveatContext
			return
		}
		val, err := astValueToInterface(v.Value)
		if err != nil {
			iterErr = err
			return
		}
		m[string(ks)] = val
	})
	if iterErr != nil {
		return nil, iterErr
	}
	return structpb.NewStruct(m)
}

var errMalformedCaveatContext = subjectError("caveat_context must be an object with string keys")

// astValueToInterface walks an ast.Value and returns the Go any equivalent
// suitable for structpb.NewStruct.
func astValueToInterface(v ast.Value) (any, error) {
	switch x := v.(type) {
	case ast.Null:
		return nil, nil
	case ast.Boolean:
		return bool(x), nil
	case ast.Number:
		if i, ok := x.Int64(); ok {
			return i, nil
		}
		f, ok := x.Float64()
		if !ok {
			return nil, subjectError("number out of range")
		}
		return f, nil
	case ast.String:
		return string(x), nil
	case *ast.Array:
		out := make([]any, 0, x.Len())
		for i := 0; i < x.Len(); i++ {
			val, err := astValueToInterface(x.Elem(i).Value)
			if err != nil {
				return nil, err
			}
			out = append(out, val)
		}
		return out, nil
	case ast.Object:
		out := make(map[string]any, x.Len())
		var iterErr error
		x.Foreach(func(k, vt *ast.Term) {
			if iterErr != nil {
				return
			}
			ks, ok := k.Value.(ast.String)
			if !ok {
				iterErr = errMalformedCaveatContext
				return
			}
			val, err := astValueToInterface(vt.Value)
			if err != nil {
				iterErr = err
				return
			}
			out[string(ks)] = val
		})
		if iterErr != nil {
			return nil, iterErr
		}
		return out, nil
	case ast.Set:
		return nil, subjectError("ast.Set is not representable in structpb")
	default:
		return nil, subjectError("unsupported ast value type")
	}
}

// structpbToMap unwraps a *structpb.Struct back to map[string]any for the
// Engine APIs that take a Go map (CheckPermissionWithCaveat / LookupResourcesWithCaveat).
func structpbToMap(s *structpb.Struct) map[string]any {
	if s == nil {
		return nil
	}
	return s.AsMap()
}
